"use client";
import Link from 'next/link';
import { Search, Heart, User, Settings, Accessibility } from 'lucide-react';
import { useState } from 'react';

export default function Navbar() {
  const [isHighContrast, setIsHighContrast] = useState(false);

  const toggleHighContrast = () => {
    setIsHighContrast(!isHighContrast);
    document.documentElement.classList.toggle('high-contrast');
  };

  return (
    <nav className="bg-white border-b border-slate-200 sticky top-0 z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-16 items-center">
          <div className="flex items-center gap-8">
            <Link href="/" className="flex items-center">
              <span className="text-2xl font-black text-primary-600 tracking-tighter">Access<span className="text-accent-600">Health</span></span>
            </Link>
            
            <div className="hidden md:flex items-center bg-slate-100 rounded-full px-4 py-2 w-96">
              <Search className="text-slate-400 mr-2" size={18} />
              <input 
                type="text" 
                placeholder="Search hospitals, clinics..." 
                className="bg-transparent border-none focus:outline-none w-full text-sm"
              />
            </div>
          </div>

          <div className="flex items-center gap-4">
            <button 
              onClick={toggleHighContrast}
              className={`p-2 rounded-full transition-colors ${isHighContrast ? 'bg-yellow-400 text-black' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'}`}
              title="Toggle High Contrast"
              aria-label="Toggle high contrast mode"
            >
              <Accessibility size={20} />
            </button>
            
            <Link href="/dashboard" className="hidden sm:flex items-center gap-1 text-slate-600 hover:text-primary-600 font-medium text-sm">
              <User size={18} />
              <span>Dashboard</span>
            </Link>

            <Link href="/submit" className="bg-primary-600 text-white px-4 py-2 rounded-lg font-bold text-sm hover:bg-primary-700 transition-all">
              Add Facility
            </Link>
          </div>
        </div>
      </div>
    </nav>
  );
}
